import{_ as i,o as a,c as t,ag as o}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Aliasuri Editor | Dotfiles (RO)","titleTemplate":":title","description":"Comenzi scurte pentru editare. Prezentare generală pentru Dotfiles v0.2.495. Compatibil cu macOS, Linux și WSL prin Dotfiles.","frontmatter":{"title":"Aliasuri Editor | Dotfiles","description":"Comenzi scurte pentru editare. Prezentare generală pentru Dotfiles v0.2.495. Compatibil cu macOS, Linux și WSL prin Dotfiles.","lang":"ro-RO","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Aliasuri Editor | Previzualizare Dotfiles","canonical":"/ro/aliases/editor/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Aliasuri Editor","pageType":"docs","schemaType":"WebPage","permalink":"/ro/aliases/editor/"},"headers":[],"relativePath":"ro/aliases/editor/index.md","filePath":"ro/aliases/editor/index.md","lastUpdated":1773010926000}'),r={name:"ro/aliases/editor/index.md"};function l(d,e,c,n,s,u){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="aliasuri-editor" tabindex="-1">Aliasuri Editor <a class="header-anchor" href="#aliasuri-editor" aria-label="Permalink to &quot;Aliasuri Editor&quot;">​</a></h1><p>Comenzi scurte pentru editare.</p><p>Această pagină prezintă un grup de aliasuri și scurtăturile sale de comandă obișnuite. Citiți-o mai întâi pentru a înțelege convențiile de denumire, intrările așteptate și tiparele de execuție sigure. Apoi deschideți anexa de referință pentru inventarul complet de comenzi și sintaxa exactă. Aceste aliasuri reduc tastarea repetitivă și mențin un comportament consistent pe macOS, Linux și WSL.</p><h2 id="cand-se-utilizeaza" tabindex="-1">Când se utilizează <a class="header-anchor" href="#cand-se-utilizeaza" aria-label="Permalink to &quot;Când se utilizează&quot;">​</a></h2><p>Utilizați această pagină înainte de lucrul zilnic în shell când aveți nevoie de tipare de comandă previzibile.</p><h2 id="ce-este-inclus" tabindex="-1">Ce este inclus <a class="header-anchor" href="#ce-este-inclus" aria-label="Permalink to &quot;Ce este inclus&quot;">​</a></h2><ul><li>Aliasuri: 30</li><li>Funcții helper: 2</li><li>Fișiere sursă: 1</li></ul><h2 id="exemple-rapide" tabindex="-1">Exemple rapide <a class="header-anchor" href="#exemple-rapide" aria-label="Permalink to &quot;Exemple rapide&quot;">​</a></h2><ul><li><code>e</code> → <code>${EDITOR}</code></li><li><code>edit</code> → <code>${EDITOR}</code></li><li><code>editor</code> → <code>${EDITOR}</code></li><li><code>em</code> → <code>emacs</code></li><li><code>emacs-nw</code> → <code>emacs -nw</code></li><li><code>emacsc</code> → <code>emacsclient</code></li><li><code>emacsrc</code> → <code>emacs ~/.emacs</code></li><li><code>et</code> → <code>&quot;emacs -nw&quot; # Mod terminal</code></li><li><code>mate</code> → <code>${EDITOR}</code></li><li><code>n</code> → <code>${EDITOR}</code></li><li><code>nanorc</code> → <code>nano &quot;${HOME}/.nanorc&quot;</code></li><li><code>ne</code> → <code>nanoedit</code></li></ul><h2 id="pasul-urmator" tabindex="-1">Pasul următor <a class="header-anchor" href="#pasul-urmator" aria-label="Permalink to &quot;Pasul următor&quot;">​</a></h2><p>Deschideți lista completă:</p>',11)])])}const h=i(r,[["render",l]]);export{m as __pageData,h as default};
